commandLine.original:
$css = @'
@import "tailwindcss";

/* ─── Cyberpunk Theme ─────────────────────────────────────────── */
@theme {
  --color-cp-black:   #050a0e;
  --color-cp-surface: #0d1117;
  --color-cp-panel:   #111827;
  --color-cp-yellow:  #fcee09;
  --color-cp-cyan:    #00f0ff;
  --color-cp-red:     #ff003c;
  --color-cp-muted:   #6b7280;
  --color-cp-border:  #1f2937;

  --font-orbitron: 'Orbitron', sans-serif;
  --font-rajdhani: 'Rajdhani', sans-serif;
  --font-mono:     'Share Tech Mono', monospace;
}

/* ─── Globals ─────────────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; }
html { scroll-behavior: smooth; }
body {
  margin: 0;
  background-color: #050a0e;
  color: #e5e7eb;
  font-family: 'Share Tech Mono', monospace;
  -webkit-font-smoothing: antialiased;
  overflow-x: hidden;
}

/* ─── Neon Glow Utilities ────────────────────────────────────── */
.neon-yellow { text-shadow: 0 0 6px #fcee09, 0 0 20px #fcee0966; }
.neon-cyan   { text-shadow: 0 0 6px #00f0ff, 0 0 20px #00f0ff66; }
.neon-red    { text-shadow: 0 0 6px #ff003c, 0 0 20px #ff003c66; }

/* ─── Card Glow on Hover ─────────────────────────────────────── */
.card-glow { transition: box-shadow 0.25s ease, border-color 0.25s ease; }
.card-glow:hover {
  box-shadow: 0 0 18px #00f0ff33, 0 0 4px #00f0ff22;
  border-color: #00f0ff66 !important;
}

/* ─── Scanlines overlay ──────────────────────────────────────── */
.scanlines::after {
  content: '';
  position: absolute;
  inset: 0;
  background: repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,0,0,0.07) 2px, rgba(0,0,0,0.07) 4px);
  pointer-events: none;
  z-index: 1;
}

/* ─── Glitch Animation ───────────────────────────────────────── */
@keyframes glitch-1 {
  0%, 100% { clip-path: inset(0 0 98% 0); transform: translate(-2px, 0); }
  20%       { clip-path: inset(30% 0 50% 0); transform: translate(2px, 0); }
  40%       { clip-path: inset(70% 0 10% 0); transform: translate(-1px, 0); }
}
@keyframes glitch-2 {
  0%, 100% { clip-path: inset(60% 0 20% 0); transform: translate(2px, 0); opacity: 0.8; }
  30%       { clip-path: inset(10% 0 80% 0); transform: translate(-2px, 0); }
  60%       { clip-path: inset(40% 0 40% 0); transform: translate(1px, 0); }
}
.glitch { position: relative; }
.glitch::before, .glitch::after { content: attr(data-text); position: absolute; inset: 0; display: block; font: inherit; color: inherit; }
.glitch:hover::before { color: #00f0ff; animation: glitch-1 0.4s steps(2) infinite; }
.glitch:hover::after  { color: #ff003c; animation: glitch-2 0.4s steps(2) infinite; }

/* ─── Corner-cut card ────────────────────────────────────────── */
.clip-corner { clip-path: polygon(0 0, calc(100% - 14px) 0, 100% 14px, 100% 100%, 0 100%); }

/* ─── Dot grid background ────────────────────────────────────── */
.dot-grid {
  background-image: radial-gradient(rgba(0,240,255,0.10) 1px, transparent 1px);
  background-size: 28px 28px;
}

/* ─── Section label ──────────────────────────────────────────── */
.section-label {
  font-family: 'Share Tech Mono', monospace;
  font-size: 0.75rem;
  letter-spacing: 0.15em;
  color: #00f0ff;
  text-transform: uppercase;
}
'@
Set-Content "c:\Users\david\OneDrive\Documents\Code\Portfolio\portfolio\src\index.css" -Value $css -Encoding UTF8

