        <motion.div
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, margin: '-40px' }}
          className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6"
        >
          {reshadeProjects.map(p => (
            <ReShadeCard key={p.id} project={p} />
          ))}
        </motion.div>
      </div>
    </section>
  );
}
